		function URL()
{
	var url;				
	np = new NomadProxy("", ut);
	var nSQL = np.SQLService();
	url = nSQL.GetOBJ(Ctrl("main").getResource("QRY_PARAMETRO"), "");
	var pCall = url.d_valor + "/generatepages.aspx";


	//ANTES: hacia la invocacion i visualizacion desde un iframe
	//Ctrl("tablas").SetURL(pCall);

	//AHORA: llama a ventana modal para no tener problemas de seguridad con el seteo (x-frame-options sameorigin) del IIS
  OpenWindowCentered(pCall, 0.50, 0.50);
}       

function OpenWindowCentered(p,w,h)
{
	var width = (screen.availWidth*w);
	var height = (screen.availHeight*h);
	var left = (screen.width/2)-(width/2);
  var top = (screen.height/2)-(height/2);
  window.open(p, '', 'channelmode=no,directories=no,fullscreen=no,location=no,menubar=no,resizable=yes,scrollbars=yes,status=no,titlebar=no,toolbar=no,left='+left+',top='+top+',width='+width+',height='+height);
}
